CREATE TABLE "PUBLIC"."PLAYLISTS"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1) NOT NULL,
    "USER_ID" BIGINT NOT NULL,
    "NAME" VARCHAR(255) NOT NULL,
    "CREATED_AT" TIMESTAMP WITH TIME ZONE NOT NULL,
    "UPDATED_AT" TIMESTAMP WITH TIME ZONE NOT NULL
);
ALTER TABLE "PUBLIC"."PLAYLISTS" ADD CONSTRAINT "PUBLIC"."PK_PLAYLISTS" PRIMARY KEY("ID");
ALTER TABLE "PUBLIC"."PLAYLISTS" ADD CONSTRAINT "PUBLIC"."FK_PLAYLIST_USER" FOREIGN KEY("USER_ID") REFERENCES "PUBLIC"."USERS"("ID");
CREATE INDEX "PUBLIC"."IDX_PLAYLIST_USER" ON "PUBLIC"."PLAYLISTS"("USER_ID");

CREATE TABLE "PUBLIC"."PLAYLIST_TRACKS"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1) NOT NULL,
    "PLAYLIST_ID" BIGINT NOT NULL,
    "TRACK_ID" BIGINT NOT NULL,
    "POSITION" INT NOT NULL,
    "ADDED_AT" TIMESTAMP WITH TIME ZONE NOT NULL
);
ALTER TABLE "PUBLIC"."PLAYLIST_TRACKS" ADD CONSTRAINT "PUBLIC"."PK_PLAYLIST_TRACKS" PRIMARY KEY("ID");
ALTER TABLE "PUBLIC"."PLAYLIST_TRACKS" ADD CONSTRAINT "PUBLIC"."FK_PT_PLAYLIST" FOREIGN KEY("PLAYLIST_ID") REFERENCES "PUBLIC"."PLAYLISTS"("ID") ON DELETE CASCADE;
ALTER TABLE "PUBLIC"."PLAYLIST_TRACKS" ADD CONSTRAINT "PUBLIC"."FK_PT_TRACK" FOREIGN KEY("TRACK_ID") REFERENCES "PUBLIC"."TRACKS"("ID") ON DELETE CASCADE;
ALTER TABLE "PUBLIC"."PLAYLIST_TRACKS" ADD CONSTRAINT "PUBLIC"."UK_PLAYLIST_TRACK" UNIQUE("PLAYLIST_ID", "TRACK_ID");
CREATE INDEX "PUBLIC"."IDX_PT_PLAYLIST_POS" ON "PUBLIC"."PLAYLIST_TRACKS"("PLAYLIST_ID", "POSITION");
